import{_ as o,o as a,c as d,ai as i}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"message","description":"","frontmatter":{"summary":"CLI reference for `opensoul message` (send + channel actions)","read_when":["Adding or modifying message CLI actions","Changing outbound channel behavior"],"title":"message"},"headers":[],"relativePath":"cli/message.md","filePath":"cli/message.md","lastUpdated":null}'),l={name:"cli/message.md"};function s(c,e,n,t,r,p){return a(),d("div",null,[...e[0]||(e[0]=[i(`<h1 id="opensoul-message" tabindex="-1"><a class="header-anchor" href="#opensoul-message">#</a> <code>opensoul message</code></h1><p>Single outbound command for sending messages and channel actions (Discord/Google Chat/Slack/Mattermost (plugin)/Telegram/WhatsApp/Signal/iMessage/MS Teams).</p><h2 id="usage" tabindex="-1"><a class="header-anchor" href="#usage">#</a> Usage</h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message &lt;subcommand&gt; [flags]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Channel selection:</p><ul><li><code>--channel</code> required if more than one channel is configured.</li><li>If exactly one channel is configured, it becomes the default.</li><li>Values: <code>whatsapp|telegram|discord|googlechat|slack|mattermost|signal|imessage|msteams</code> (Mattermost requires plugin)</li></ul><p>Target formats (<code>--target</code>):</p><ul><li>WhatsApp: E.164 or group JID</li><li>Telegram: chat id or <code>@username</code></li><li>Discord: <code>channel:&lt;id&gt;</code> or <code>user:&lt;id&gt;</code> (or <code>&lt;@id&gt;</code> mention; raw numeric ids are treated as channels)</li><li>Google Chat: <code>spaces/&lt;spaceId&gt;</code> or <code>users/&lt;userId&gt;</code></li><li>Slack: <code>channel:&lt;id&gt;</code> or <code>user:&lt;id&gt;</code> (raw channel id is accepted)</li><li>Mattermost (plugin): <code>channel:&lt;id&gt;</code>, <code>user:&lt;id&gt;</code>, or <code>@username</code> (bare ids are treated as channels)</li><li>Signal: <code>+E.164</code>, <code>group:&lt;id&gt;</code>, <code>signal:+E.164</code>, <code>signal:group:&lt;id&gt;</code>, or <code>username:&lt;name&gt;</code>/<code>u:&lt;name&gt;</code></li><li>iMessage: handle, <code>chat_id:&lt;id&gt;</code>, <code>chat_guid:&lt;guid&gt;</code>, or <code>chat_identifier:&lt;id&gt;</code></li><li>MS Teams: conversation id (<code>19:...@thread.tacv2</code>) or <code>conversation:&lt;id&gt;</code> or <code>user:&lt;aad-object-id&gt;</code></li></ul><p>Name lookup:</p><ul><li>For supported providers (Discord/Slack/etc), channel names like <code>Help</code> or <code>#help</code> are resolved via the directory cache.</li><li>On cache miss, OpenSoul will attempt a live directory lookup when the provider supports it.</li></ul><h2 id="common-flags" tabindex="-1"><a class="header-anchor" href="#common-flags">#</a> Common flags</h2><ul><li><code>--channel &lt;name&gt;</code></li><li><code>--account &lt;id&gt;</code></li><li><code>--target &lt;dest&gt;</code> (target channel or user for send/poll/read/etc)</li><li><code>--targets &lt;name&gt;</code> (repeat; broadcast only)</li><li><code>--json</code></li><li><code>--dry-run</code></li><li><code>--verbose</code></li></ul><h2 id="actions" tabindex="-1"><a class="header-anchor" href="#actions">#</a> Actions</h2><h3 id="core" tabindex="-1"><a class="header-anchor" href="#core">#</a> Core</h3><ul><li><p><code>send</code></p><ul><li>Channels: WhatsApp/Telegram/Discord/Google Chat/Slack/Mattermost (plugin)/Signal/iMessage/MS Teams</li><li>Required: <code>--target</code>, plus <code>--message</code> or <code>--media</code></li><li>Optional: <code>--media</code>, <code>--reply-to</code>, <code>--thread-id</code>, <code>--gif-playback</code></li><li>Telegram only: <code>--buttons</code> (requires <code>channels.telegram.capabilities.inlineButtons</code> to allow it)</li><li>Telegram only: <code>--thread-id</code> (forum topic id)</li><li>Slack only: <code>--thread-id</code> (thread timestamp; <code>--reply-to</code> uses the same field)</li><li>WhatsApp only: <code>--gif-playback</code></li></ul></li><li><p><code>poll</code></p><ul><li>Channels: WhatsApp/Discord/MS Teams</li><li>Required: <code>--target</code>, <code>--poll-question</code>, <code>--poll-option</code> (repeat)</li><li>Optional: <code>--poll-multi</code></li><li>Discord only: <code>--poll-duration-hours</code>, <code>--message</code></li></ul></li><li><p><code>react</code></p><ul><li>Channels: Discord/Google Chat/Slack/Telegram/WhatsApp/Signal</li><li>Required: <code>--message-id</code>, <code>--target</code></li><li>Optional: <code>--emoji</code>, <code>--remove</code>, <code>--participant</code>, <code>--from-me</code>, <code>--target-author</code>, <code>--target-author-uuid</code></li><li>Note: <code>--remove</code> requires <code>--emoji</code> (omit <code>--emoji</code> to clear own reactions where supported; see /tools/reactions)</li><li>WhatsApp only: <code>--participant</code>, <code>--from-me</code></li><li>Signal group reactions: <code>--target-author</code> or <code>--target-author-uuid</code> required</li></ul></li><li><p><code>reactions</code></p><ul><li>Channels: Discord/Google Chat/Slack</li><li>Required: <code>--message-id</code>, <code>--target</code></li><li>Optional: <code>--limit</code></li></ul></li><li><p><code>read</code></p><ul><li>Channels: Discord/Slack</li><li>Required: <code>--target</code></li><li>Optional: <code>--limit</code>, <code>--before</code>, <code>--after</code></li><li>Discord only: <code>--around</code></li></ul></li><li><p><code>edit</code></p><ul><li>Channels: Discord/Slack</li><li>Required: <code>--message-id</code>, <code>--message</code>, <code>--target</code></li></ul></li><li><p><code>delete</code></p><ul><li>Channels: Discord/Slack/Telegram</li><li>Required: <code>--message-id</code>, <code>--target</code></li></ul></li><li><p><code>pin</code> / <code>unpin</code></p><ul><li>Channels: Discord/Slack</li><li>Required: <code>--message-id</code>, <code>--target</code></li></ul></li><li><p><code>pins</code> (list)</p><ul><li>Channels: Discord/Slack</li><li>Required: <code>--target</code></li></ul></li><li><p><code>permissions</code></p><ul><li>Channels: Discord</li><li>Required: <code>--target</code></li></ul></li><li><p><code>search</code></p><ul><li>Channels: Discord</li><li>Required: <code>--guild-id</code>, <code>--query</code></li><li>Optional: <code>--channel-id</code>, <code>--channel-ids</code> (repeat), <code>--author-id</code>, <code>--author-ids</code> (repeat), <code>--limit</code></li></ul></li></ul><h3 id="threads" tabindex="-1"><a class="header-anchor" href="#threads">#</a> Threads</h3><ul><li><p><code>thread create</code></p><ul><li>Channels: Discord</li><li>Required: <code>--thread-name</code>, <code>--target</code> (channel id)</li><li>Optional: <code>--message-id</code>, <code>--message</code>, <code>--auto-archive-min</code></li></ul></li><li><p><code>thread list</code></p><ul><li>Channels: Discord</li><li>Required: <code>--guild-id</code></li><li>Optional: <code>--channel-id</code>, <code>--include-archived</code>, <code>--before</code>, <code>--limit</code></li></ul></li><li><p><code>thread reply</code></p><ul><li>Channels: Discord</li><li>Required: <code>--target</code> (thread id), <code>--message</code></li><li>Optional: <code>--media</code>, <code>--reply-to</code></li></ul></li></ul><h3 id="emojis" tabindex="-1"><a class="header-anchor" href="#emojis">#</a> Emojis</h3><ul><li><p><code>emoji list</code></p><ul><li>Discord: <code>--guild-id</code></li><li>Slack: no extra flags</li></ul></li><li><p><code>emoji upload</code></p><ul><li>Channels: Discord</li><li>Required: <code>--guild-id</code>, <code>--emoji-name</code>, <code>--media</code></li><li>Optional: <code>--role-ids</code> (repeat)</li></ul></li></ul><h3 id="stickers" tabindex="-1"><a class="header-anchor" href="#stickers">#</a> Stickers</h3><ul><li><p><code>sticker send</code></p><ul><li>Channels: Discord</li><li>Required: <code>--target</code>, <code>--sticker-id</code> (repeat)</li><li>Optional: <code>--message</code></li></ul></li><li><p><code>sticker upload</code></p><ul><li>Channels: Discord</li><li>Required: <code>--guild-id</code>, <code>--sticker-name</code>, <code>--sticker-desc</code>, <code>--sticker-tags</code>, <code>--media</code></li></ul></li></ul><h3 id="roles-channels-members-voice" tabindex="-1"><a class="header-anchor" href="#roles-channels-members-voice">#</a> Roles / Channels / Members / Voice</h3><ul><li><code>role info</code> (Discord): <code>--guild-id</code></li><li><code>role add</code> / <code>role remove</code> (Discord): <code>--guild-id</code>, <code>--user-id</code>, <code>--role-id</code></li><li><code>channel info</code> (Discord): <code>--target</code></li><li><code>channel list</code> (Discord): <code>--guild-id</code></li><li><code>member info</code> (Discord/Slack): <code>--user-id</code> (+ <code>--guild-id</code> for Discord)</li><li><code>voice status</code> (Discord): <code>--guild-id</code>, <code>--user-id</code></li></ul><h3 id="events" tabindex="-1"><a class="header-anchor" href="#events">#</a> Events</h3><ul><li><code>event list</code> (Discord): <code>--guild-id</code></li><li><code>event create</code> (Discord): <code>--guild-id</code>, <code>--event-name</code>, <code>--start-time</code><ul><li>Optional: <code>--end-time</code>, <code>--desc</code>, <code>--channel-id</code>, <code>--location</code>, <code>--event-type</code></li></ul></li></ul><h3 id="moderation-discord" tabindex="-1"><a class="header-anchor" href="#moderation-discord">#</a> Moderation (Discord)</h3><ul><li><code>timeout</code>: <code>--guild-id</code>, <code>--user-id</code> (optional <code>--duration-min</code> or <code>--until</code>; omit both to clear timeout)</li><li><code>kick</code>: <code>--guild-id</code>, <code>--user-id</code> (+ <code>--reason</code>)</li><li><code>ban</code>: <code>--guild-id</code>, <code>--user-id</code> (+ <code>--delete-days</code>, <code>--reason</code>) <ul><li><code>timeout</code> also supports <code>--reason</code></li></ul></li></ul><h3 id="broadcast" tabindex="-1"><a class="header-anchor" href="#broadcast">#</a> Broadcast</h3><ul><li><code>broadcast</code><ul><li>Channels: any configured channel; use <code>--channel all</code> to target all providers</li><li>Required: <code>--targets</code> (repeat)</li><li>Optional: <code>--message</code>, <code>--media</code>, <code>--dry-run</code></li></ul></li></ul><h2 id="examples" tabindex="-1"><a class="header-anchor" href="#examples">#</a> Examples</h2><p>Send a Discord reply:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message send --channel discord \\</span></span>
<span class="line"><span>  --target channel:123 --message &quot;hi&quot; --reply-to 456</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Create a Discord poll:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message poll --channel discord \\</span></span>
<span class="line"><span>  --target channel:123 \\</span></span>
<span class="line"><span>  --poll-question &quot;Snack?&quot; \\</span></span>
<span class="line"><span>  --poll-option Pizza --poll-option Sushi \\</span></span>
<span class="line"><span>  --poll-multi --poll-duration-hours 48</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Send a Teams proactive message:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message send --channel msteams \\</span></span>
<span class="line"><span>  --target conversation:19:abc@thread.tacv2 --message &quot;hi&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Create a Teams poll:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message poll --channel msteams \\</span></span>
<span class="line"><span>  --target conversation:19:abc@thread.tacv2 \\</span></span>
<span class="line"><span>  --poll-question &quot;Lunch?&quot; \\</span></span>
<span class="line"><span>  --poll-option Pizza --poll-option Sushi</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>React in Slack:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message react --channel slack \\</span></span>
<span class="line"><span>  --target C123 --message-id 456 --emoji &quot;✅&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>React in a Signal group:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message react --channel signal \\</span></span>
<span class="line"><span>  --target signal:group:abc123 --message-id 1737630212345 \\</span></span>
<span class="line"><span>  --emoji &quot;✅&quot; --target-author-uuid 123e4567-e89b-12d3-a456-426614174000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Send Telegram inline buttons:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensoul message send --channel telegram --target @mychat --message &quot;Choose:&quot; \\</span></span>
<span class="line"><span>  --buttons &#39;[ [{&quot;text&quot;:&quot;Yes&quot;,&quot;callback_data&quot;:&quot;cmd:yes&quot;}], [{&quot;text&quot;:&quot;No&quot;,&quot;callback_data&quot;:&quot;cmd:no&quot;}] ]&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,44)])])}const m=o(l,[["render",s]]);export{h as __pageData,m as default};
